## API Security Testing - Best Practices

### 1. Implement Proper Authentication

**Use strong, standard authentication mechanisms:**

```python
# Best Practice: OAuth 2.0 with short-lived access tokens
# Access token: 15 minutes expiry
# Refresh token: 7 days expiry, single-use, rotated on each use

import jwt
import datetime
import secrets

def create_access_token(user_id, roles, secret_key):
    payload = {
        'sub': str(user_id),
        'roles': roles,
        'iat': datetime.datetime.utcnow(),
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=15),
        'jti': secrets.token_hex(16),  # Unique token ID for revocation
    }
    return jwt.encode(payload, secret_key, algorithm='RS256')  # Use asymmetric signing

def create_refresh_token(user_id):
    token = secrets.token_urlsafe(64)
    # Store hash in database with expiry and user association
    store_refresh_token(
        user_id=user_id,
        token_hash=hashlib.sha256(token.encode()).hexdigest(),
        expires_at=datetime.datetime.utcnow() + datetime.timedelta(days=7),
        is_used=False
    )
    return token
```

**API Key Best Practices:**
- Generate keys with sufficient entropy (at least 32 bytes / 256 bits)
- Hash API keys before storing in the database (like passwords)
- Scope keys to specific operations and resources
- Implement key rotation without downtime
- Transmit keys in headers, never in URLs (URLs are logged)

### 2. Enforce Authorization on Every Request

```python
from functools import wraps

def require_permission(*permissions):
    """Decorator that checks both authentication and specific permissions."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # 1. Verify token
            token = extract_token(request)
            if not token:
                return {'error': 'Authentication required'}, 401

            # 2. Validate and decode
            try:
                claims = jwt.decode(token, PUBLIC_KEY, algorithms=['RS256'])
            except jwt.ExpiredSignatureError:
                return {'error': 'Token expired'}, 401
            except jwt.InvalidTokenError:
                return {'error': 'Invalid token'}, 401

            # 3. Check revocation
            if is_token_revoked(claims['jti']):
                return {'error': 'Token revoked'}, 401

            # 4. Check permissions
            user_permissions = set(claims.get('permissions', []))
            if not set(permissions).issubset(user_permissions):
                return {'error': 'Insufficient permissions'}, 403

            # 5. Set current user context
            g.current_user = claims
            return f(*args, **kwargs)
        return decorated_function
    return decorator

# Usage
@app.route('/api/users/<user_id>/orders')
@require_permission('orders:read')
def get_user_orders(user_id):
    # 6. Object-level authorization check
    if g.current_user['sub'] != user_id and 'admin' not in g.current_user.get('roles', []):
        return {'error': 'Access denied'}, 403
    # Proceed with authorized request
```

### 3. Validate and Sanitize All Input

```python
from marshmallow import Schema, fields, validate, pre_load
import bleach

class CreateOrderSchema(Schema):
    product_id = fields.UUID(required=True)
    quantity = fields.Int(required=True, validate=validate.Range(min=1, max=100))
    shipping_address = fields.Str(
        required=True,
        validate=validate.Length(min=10, max=500)
    )
    notes = fields.Str(validate=validate.Length(max=1000))

    # Explicitly define allowed fields - anything else is rejected
    class Meta:
        unknown = 'EXCLUDE'  # Silently strip unknown fields (prevents mass assignment)

    @pre_load
    def sanitize_strings(self, data, **kwargs):
        for key in ('shipping_address', 'notes'):
            if key in data and isinstance(data[key], str):
                data[key] = bleach.clean(data[key], tags=[], strip=True)
        return data
```

### 4. Implement Proper Rate Limiting

```python
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address

limiter = Limiter(
    app=app,
    key_func=get_remote_address,
    default_limits=["100 per minute"],
    storage_uri="redis://localhost:6379"
)

# Different limits for different endpoint sensitivity levels
@app.route('/api/auth/login', methods=['POST'])
@limiter.limit("5 per minute")  # Strict limit on login
def login():
    pass

@app.route('/api/auth/forgot-password', methods=['POST'])
@limiter.limit("3 per hour")  # Very strict on password reset
def forgot_password():
    pass

@app.route('/api/data/search')
@limiter.limit("30 per minute")  # Moderate for search
def search():
    pass

@app.route('/api/data/export')
@limiter.limit("5 per hour")  # Strict for expensive operations
def export_data():
    pass
```

### 5. Control Response Data

Never return more data than the client needs:

```python
# BAD: Returns entire user object including sensitive fields
@app.route('/api/users/<id>')
def get_user(id):
    user = User.query.get(id)
    return jsonify(user.__dict__)  # Exposes password_hash, internal_notes, etc.

# GOOD: Use explicit serialization with field selection
class UserPublicSchema(Schema):
    id = fields.UUID()
    username = fields.Str()
    display_name = fields.Str()
    avatar_url = fields.Str()
    created_at = fields.DateTime()
    # password_hash, email, phone, internal_notes are NOT included

class UserPrivateSchema(UserPublicSchema):
    email = fields.Email()
    phone = fields.Str()
    # Only returned when user views their own profile

@app.route('/api/users/<id>')
@require_auth
def get_user(id):
    user = User.query.get_or_404(id)
    if g.current_user['sub'] == str(id):
        return UserPrivateSchema().dump(user)
    return UserPublicSchema().dump(user)
```

### 6. Secure API Error Responses

```python
# Return consistent error format without leaking internals
@app.errorhandler(Exception)
def handle_error(error):
    if isinstance(error, ValidationError):
        return {'error': 'Validation failed', 'details': error.messages}, 400
    elif isinstance(error, NotFound):
        return {'error': 'Resource not found'}, 404
    elif isinstance(error, Forbidden):
        return {'error': 'Access denied'}, 403
    else:
        # Log the real error server-side
        app.logger.error(f"Unhandled error: {error}", exc_info=True)
        # Return generic message to client
        return {'error': 'Internal server error'}, 500
```

### 7. Version and Deprecate APIs Safely

- Maintain an inventory of all API versions in production
- Set sunset dates for old versions and communicate them via `Sunset` and `Deprecation` headers
- Ensure security patches are applied to all active versions
- Monitor traffic to deprecated versions and enforce migration deadlines
- Remove old versions completely once deprecated

### 8. Log Security Events

```python
import logging

security_logger = logging.getLogger('security')

def log_security_event(event_type, details, request, severity='INFO'):
    security_logger.log(
        getattr(logging, severity),
        json.dumps({
            'event': event_type,
            'ip': request.remote_addr,
            'user_agent': request.headers.get('User-Agent'),
            'user_id': g.get('current_user', {}).get('sub'),
            'endpoint': request.path,
            'method': request.method,
            'timestamp': datetime.utcnow().isoformat(),
            'details': details
        })
    )

# Log authentication failures, authorization failures, input validation
# failures, rate limit hits, and any suspicious activity
```

