## API Security Testing - Tips & Tricks

### 1. Use Postman Collections for Systematic Testing

Organize your API security tests into Postman collections with pre-request scripts and tests:

```javascript
// Postman pre-request script: automatically set auth token
pm.sendRequest({
    url: pm.environment.get('base_url') + '/api/auth/login',
    method: 'POST',
    header: {'Content-Type': 'application/json'},
    body: {
        mode: 'raw',
        raw: JSON.stringify({
            username: pm.environment.get('test_username'),
            password: pm.environment.get('test_password')
        })
    }
}, function(err, res) {
    pm.environment.set('auth_token', res.json().token);
});

// Postman test script: check security headers
pm.test('Security headers present', function() {
    pm.response.to.have.header('X-Content-Type-Options');
    pm.response.to.have.header('X-Frame-Options');
    pm.response.to.not.have.header('Server');
});

pm.test('No sensitive data in response', function() {
    var body = pm.response.text();
    pm.expect(body).to.not.include('password');
    pm.expect(body).to.not.include('secret');
    pm.expect(body).to.not.include('token');
});
```

### 2. Fuzz API Parameters Quickly

```python
import itertools
import string

def generate_fuzz_values(field_type='string'):
    """Generate common fuzz values for API testing."""
    common = [
        None, '', ' ', '\t', '\n', '\r\n',
        'null', 'undefined', 'NaN', 'Infinity',
        True, False, 0, -1, 1.5,
        [], {}, [None], {'key': 'value'},
    ]

    if field_type == 'string':
        common.extend([
            'A' * 10000,              # Very long string
            '<script>alert(1)</script>',  # XSS
            "' OR '1'='1",            # SQL injection
            '${7*7}',                 # Template injection
            '../../../etc/passwd',    # Path traversal
            '\x00',                   # Null byte
            '��',                    # Unicode edge cases
        ])
    elif field_type == 'number':
        common.extend([
            0, -1, -999999, 999999999,
            1.7976931348623157e+308,  # Max float
            float('inf'), float('-inf'),
            '1; DROP TABLE users',    # SQL via number field
        ])
    elif field_type == 'email':
        common.extend([
            'test@', '@test.com', 'test@test', 'a'*256 + '@test.com',
            'test@test.com\nBcc: attacker@evil.com',  # Email header injection
        ])

    return common

def fuzz_endpoint(url, base_payload, field_to_fuzz, token):
    """Fuzz a single field in an API request."""
    headers = {'Authorization': f'Bearer {token}', 'Content-Type': 'application/json'}
    results = []

    for fuzz_value in generate_fuzz_values():
        payload = {**base_payload, field_to_fuzz: fuzz_value}
        try:
            resp = requests.post(url, json=payload, headers=headers, timeout=10)
            if resp.status_code == 500:
                results.append(('SERVER ERROR', fuzz_value, resp.text[:200]))
            elif resp.status_code == 200:
                results.append(('ACCEPTED', fuzz_value, resp.text[:200]))
        except Exception as e:
            results.append(('EXCEPTION', fuzz_value, str(e)))

    return results
```

### 3. Test JWT Security Quickly

```bash
# Decode JWT from command line
echo "eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiIxMjMifQ.abc" | \
  cut -d. -f2 | base64 -d 2>/dev/null | python3 -m json.tool

# Use jwt_tool for comprehensive JWT testing
# https://github.com/ticarpi/jwt_tool
python3 jwt_tool.py <JWT_TOKEN> -C -d /path/to/wordlist.txt  # Crack HMAC secret
python3 jwt_tool.py <JWT_TOKEN> -X a  # Test 'alg:none' bypass
python3 jwt_tool.py <JWT_TOKEN> -X k -pk public.pem  # Key confusion attack
```

### 4. GraphQL-Specific Testing Tips

```python
# Quick GraphQL introspection dump
query = """
{
  __schema {
    queryType { name }
    mutationType { name }
    types {
      name
      fields {
        name
        args { name type { name } }
        type { name kind ofType { name } }
      }
    }
  }
}
"""

# Batch query attack (test for DoS)
batch_payload = [
    {"query": "{user(id:1){name}}"} for _ in range(100)
]
resp = requests.post(graphql_url, json=batch_payload)

# Field suggestion exploitation
# Deliberately use wrong field names - GraphQL may suggest valid ones
typo_query = '{user{pasword}}'
# Response might say: "Did you mean 'password'?"
```

### 5. Quick HTTP Method Testing

```python
def test_http_methods(base_url, endpoint, token):
    """Test which HTTP methods are allowed on an endpoint."""
    headers = {'Authorization': f'Bearer {token}'}
    methods = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS', 'HEAD', 'TRACE']

    print(f"Testing {endpoint}:")
    for method in methods:
        try:
            resp = requests.request(method, f"{base_url}{endpoint}", headers=headers, timeout=5)
            if resp.status_code != 405:  # Method Not Allowed
                print(f"  {method}: {resp.status_code}")
                if method == 'TRACE' and resp.status_code == 200:
                    print("    WARNING: TRACE enabled (XST risk)")
        except requests.exceptions.RequestException:
            pass
```

### 6. Content-Type Confusion Testing

APIs sometimes behave differently based on Content-Type. Test this:

```python
def test_content_type_handling(url, payload, token):
    """Test if the API handles different content types safely."""
    content_types = [
        ('application/json', json.dumps(payload)),
        ('application/xml', '<user><name>test</name><role>admin</role></user>'),
        ('application/x-www-form-urlencoded', 'name=test&role=admin'),
        ('text/plain', str(payload)),
    ]

    for ct, body in content_types:
        headers = {
            'Authorization': f'Bearer {token}',
            'Content-Type': ct
        }
        resp = requests.post(url, data=body, headers=headers)
        print(f"  Content-Type: {ct} -> {resp.status_code}")
        if resp.status_code == 200:
            print(f"    Body accepted: {resp.text[:100]}")
```

### 7. Use Environment Variables for Sensitive Test Data

```python
import os

# Never hardcode tokens or credentials in test scripts
BASE_URL = os.environ.get('API_BASE_URL', 'http://localhost:8000')
TEST_TOKEN = os.environ.get('API_TEST_TOKEN')
ADMIN_TOKEN = os.environ.get('API_ADMIN_TOKEN')

if not TEST_TOKEN:
    raise EnvironmentError("Set API_TEST_TOKEN environment variable")
```

### 8. Check for Verbose Error Responses

Send deliberately malformed requests and check if error responses reveal internal information (stack traces, database schemas, file paths, server versions). These are goldmines for attackers.
